1	// COR24 APL Interpreter -- Tokenizer
2	// Lexes input line into token array for the parser.
3	
4	#pragma once
5	
6	// Token types
7	#define TOK_EOL     0   // end of line
8	#define TOK_NUM     1   // integer literal (value in tok_val)
9	#define TOK_IDENT   2   // user identifier (uppercase, pos in tok_val)
10	#define TOK_PLUS    3   // +
11	#define TOK_MINUS   4   // - (parser decides monadic vs dyadic)
12	#define TOK_STAR    5   // *
13	#define TOK_SLASH   6   // /
14	#define TOK_LPAREN  7   // (
15	#define TOK_RPAREN  8   // )
16	#define TOK_ASSIGN  9   // <-
17	#define TOK_RES    10   // reserved word (ID in tok_val)
18	
19	// Reserved word IDs
20	#define RES_RHO     0
21	#define RES_IOTA    1
22	#define RES_TAKE    2
23	#define RES_DROP    3
24	#define RES_REV     4
25	#define RES_CAT     5
26	
27	#define TOK_MAX    64   // max tokens per line
28	
29	// Token storage (parallel arrays)
30	int tok_type[TOK_MAX];  // token type
31	int tok_val[TOK_MAX];   // numeric value or reserved word ID
32	int tok_pos[TOK_MAX];   // start position in source line
33	int tok_count;           // number of tokens produced
34	
35	// ---- String helpers ----
36	
37	// Compare a substring of src starting at pos against a NUL-terminated word.
38	// Returns 1 if match, 0 otherwise.
39	int str_match(char *src, int pos, char *word) {
40	    int i = 0;
41	    while (word[i]) {
42	        if (src[pos + i] != word[i]) return 0;
43	        i++;
44	    }
45	    return i;  // return length of match (0 = no match since word is non-empty)
46	}
47	
48	// Check if character is a lowercase letter (a-z)
49	int is_lower(int ch) {
50	    return ch >= 97 && ch <= 122;
51	}
52	
53	// Check if character is an uppercase letter (A-Z)
54	int is_upper(int ch) {
55	    return ch >= 65 && ch <= 90;
56	}
57	
58	// Check if character is a digit (0-9)
59	int is_digit(int ch) {
60	    return ch >= 48 && ch <= 57;
61	}
62	
63	// Check if character is alphanumeric or underscore
64	int is_alnum(int ch) {
65	    return is_lower(ch) || is_upper(ch) || is_digit(ch);
66	}
67	
68	// ---- Reserved word lookup ----
69	// Returns reserved word ID if the lowercase word starting at pos matches,
70	// or -1 if not a reserved word. Sets *end to position past the word.
71	int lookup_reserved(char *src, int pos, int *end) {
72	    int len;
73	
74	    len = str_match(src, pos, "rho");
75	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
76	
77	    len = str_match(src, pos, "iota");
78	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_IOTA; }
79	
80	    len = str_match(src, pos, "take");
81	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_TAKE; }
82	
83	    len = str_match(src, pos, "drop");
84	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_DROP; }
85	
86	    len = str_match(src, pos, "rev");
87	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_REV; }
88	
89	    len = str_match(src, pos, "cat");
90	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_CAT; }
91	
92	    return -1;
93	}
94	
95	// ---- Tokenizer ----
96	// Tokenize input line into tok_type/tok_val/tok_pos arrays.
97	// Returns number of tokens (also stored in tok_count).
98	// On error, returns -1 (unrecognized character).
99	int tokenize(char *line) {
100	    int i = 0;
101	    int t = 0;
102	
103	    while (line[i] && t < TOK_MAX - 1) {
104	        // Skip whitespace
105	        if (line[i] == 32) {
106	            i++;
107	            continue;
108	        }
109	
110	        // Number: digits, or underscore followed by digit (APL negative)
111	        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
112	            tok_type[t] = TOK_NUM;
113	            tok_pos[t] = i;
114	            int end;
115	            tok_val[t] = parse_int(line, i, &end);
116	            i = end;
117	            t++;
118	            continue;
119	        }
120	
121	        // Lowercase letter: reserved word or unknown
122	        if (is_lower(line[i])) {
123	            int end;
124	            int res = lookup_reserved(line, i, &end);
125	            if (res >= 0) {
126	                tok_type[t] = TOK_RES;
127	                tok_val[t] = res;
128	                tok_pos[t] = i;
129	                i = end;
130	                t++;
131	                continue;
132	            }
133	            // Unknown lowercase word -- error
134	            return -1;
135	        }
136	
137	        // Uppercase letter: user identifier
138	        if (is_upper(line[i])) {
139	            tok_type[t] = TOK_IDENT;
140	            tok_pos[t] = i;
141	            tok_val[t] = i;  // store start position for name extraction
142	            i++;
143	            while (is_alnum(line[i])) i++;
144	            t++;
145	            continue;
146	        }
147	
148	        // Operators and punctuation
149	        if (line[i] == 43) { tok_type[t] = TOK_PLUS;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
150	        if (line[i] == 45) { tok_type[t] = TOK_MINUS;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
151	        if (line[i] == 42) { tok_type[t] = TOK_STAR;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
152	        if (line[i] == 47) { tok_type[t] = TOK_SLASH;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
153	        if (line[i] == 40) { tok_type[t] = TOK_LPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
154	        if (line[i] == 41) { tok_type[t] = TOK_RPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
155	
156	        // Assignment: <-
157	        if (line[i] == 60 && line[i + 1] == 45) {
158	            tok_type[t] = TOK_ASSIGN;
159	            tok_pos[t] = i;
160	            tok_val[t] = 0;
161	            t++;
162	            i = i + 2;
163	            continue;
164	        }
165	
166	        // Unrecognized character
167	        return -1;
168	    }
169	
170	    // Append EOL sentinel
171	    tok_type[t] = TOK_EOL;
172	    tok_pos[t] = i;
173	    tok_val[t] = 0;
174	    t++;
175	    tok_count = t;
176	    return t;
177	}
178	
179	// ---- Debug: print token list ----
180	// Useful for testing the tokenizer in isolation.
181	void tok_dump(char *line) {
182	    int i = 0;
183	    while (i < tok_count) {
184	        int ty = tok_type[i];
185	        if (ty == TOK_EOL) {
186	            io_print("EOL");
187	        } else if (ty == TOK_NUM) {
188	            io_print("NUM:");
189	            print_int(tok_val[i]);
190	        } else if (ty == TOK_IDENT) {
191	            io_print("ID:");
192	            int p = tok_val[i];
193	            while (is_alnum(line[p])) {
194	                putchar(line[p]);
195	                p++;
196	            }
197	        } else if (ty == TOK_RES) {
198	            io_print("RES:");
199	            int r = tok_val[i];
200	            if (r == RES_RHO)  io_print("rho");
201	            if (r == RES_IOTA) io_print("iota");
202	            if (r == RES_TAKE) io_print("take");
203	            if (r == RES_DROP) io_print("drop");
204	            if (r == RES_REV)  io_print("rev");
205	            if (r == RES_CAT)  io_print("cat");
206	        } else if (ty == TOK_PLUS)   { putchar(43); }
207	          else if (ty == TOK_MINUS)  { putchar(45); }
208	          else if (ty == TOK_STAR)   { putchar(42); }
209	          else if (ty == TOK_SLASH)  { putchar(47); }
